#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAXN 5000
#define MAXM 10000
struct Point {
    int x, y;
};
int compare(const void *a, const void *b) {
    struct Point *p1 = (struct Point *)a;
    struct Point *p2 = (struct Point *)b;
    if (p1->x < p2->x) return -1;
    if (p1->x > p2->x) return 1;
    return 0;
}
int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    struct Point points[n];
    for (int i = 0; i < n; i++) {
        scanf("%d %d", &points[i].x, &points[i].y);
    }
    qsort(points, n, sizeof(struct Point), compare);
    for (int i = 0; i < m; i++) {
        char query[n - 1];
        scanf("%s", query);
        int permutation[n];
        for (int j = 0; j < n; j++) {
            permutation[j] = j;
        }
        for (int j = 0; j < n - 1; j++) {
            if (query[j] == 'U') {
                if (points[permutation[j]].y > points[permutation[j + 1]].y) {
                    int temp = permutation[j];
                    permutation[j] = permutation[j + 1];
                    permutation[j + 1] = temp;
                }
            } else {
                if (points[permutation[j]].y < points[permutation[j + 1]].y) {
                    int temp = permutation[j];
                    permutation[j] = permutation[j + 1];
                    permutation[j + 1] = temp;
                }
            }
        }
        for (int j = 0; j < n; j++) {
            printf("%d ", permutation[j] + 1);
        }
        printf("\n");
    }
    return 0;
}

