struct Point {
    int x, y;
};
bool compare(const Point &p1, const Point &p2) {
    return p1.x < p2.x;
}
int main() {
    int n, m;
    cin >> n >> m;
    Point points[n];
    for (int i = 0; i < n; i++) {
        cin >> points[i].x >> points[i].y;
    }
    sort(points, points + n, compare);
    for (int i = 0; i < m; i++) {
        string query;
        cin >> query;
        int permutation[n];
        for (int j = 0; j < n; j++) {
            permutation[j] = j;
        }
        for (int j = 0; j < n - 1; j++) {
            if (query[j] == 'U') {
                if (points[permutation[j]].y > points[permutation[j + 1]].y) {
                    swap(permutation[j], permutation[j + 1]);
                }
            } else {
                if (points[permutation[j]].y < points[permutation[j + 1]].y) {
                    swap(permutation[j], permutation[j + 1]);
                }
            }
        }
        for (int j = 0; j < n; j++) {
            cout << permutation[j] + 1 << " ";
        }
        cout << endl;
    }
    return 0;
}

