const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
function nextLine() {
    return lines[idx++];
}
function nextInt() {
    return parseInt(nextLine());
}
function nextIntArray() {
    return nextLine().split(' ').map(x => parseInt(x));
}
let [n, m] = nextIntArray();
let points = [];
for (let i = 0; i < n; i++) {
    points.push(nextIntArray());
}
points.sort((a, b) => a[0] - b[0]);
for (let i = 0; i < m; i++) {
    let query = nextLine();
    let permutation = Array.from({ length: n }, (_, i) => i);
    for (let j = 0; j < n - 1; j++) {
        if (query[j] === 'U' && points[permutation[j]][1] > points[permutation[j + 1]][1]) {
            [permutation[j], permutation[j + 1]] = [permutation[j + 1], permutation[j]];
        } else if (query[j] === 'D' && points[permutation[j]][1] < points[permutation[j + 1]][1]) {
            [permutation[j], permutation[j + 1]] = [permutation[j + 1], permutation[j]];
        }
    }
    console.log(permutation.map(x => x + 1).join(' '));
